22	// This file is the wired-in reliability proof for ddx-6650fdc9 / its parent
23	// scope-locks-to-mutation-window: 5 concurrent `ddx work --watch` workers must
24	// be able to drain a shared queue while an operator shell issues bead
25	// create/update/close commands, WITHOUT either side holding .git/index.lock or
26	// .ddx/.git-tracker.lock long enough to time out the other. The locks are
27	// scoped to the mutation window only — the harness "LLM wait" (here a script
28	// `sleep-ms`) happens entirely outside any lock — so p99 hold times stay far
29	// under the configured caps (DefaultIndexLockCap=10s, DefaultTrackerLockCap=30s
30	// in internal/lockmetrics/lockcap.go).
31	//
32	// The expensive scenario (build a ddx binary, spawn 5 watcher subprocesses and
33	// 20 operator subprocesses against a fixture repo) runs exactly once via a
34	// process-wide sync.Once; the four AC-named test functions assert disjoint
35	// properties of the single captured result.
36	
37	const (
38		workerCount   = 5
39		operatorCount = 20
40		// workerBeadCount matches the contractual minimum: 5 independent ready
41		// beads for 5 workers (the bead's PROPOSED FIX). sleep-ms in the directive
42		// keeps each execution's lock-free window open long enough to overlap with
43		// the concurrent operator commands.
44		workerBeadCount = 5
45	)
46	
47	// contentionResult captures everything the four assertions need, so the
48	// scenario can run once and the fixture can be torn down before later
49	// assertions execute.
50	type contentionResult struct {
51		indexHoldMS    []float64
52		trackerHoldMS  []float64
53		operatorOutput []operatorCommand
54		workersSpawned int
55	}
