76	// contentionScenario runs the multi-worker scenario at most once per process
77	// and returns the captured result. Heavy integration work is skipped under
78	// `go test -short`.
79	func contentionScenario(t *testing.T) *contentionResult {
80		t.Helper()
81		if testing.Short() {
82			t.Skip("integration test: spawns ddx work --watch subprocesses")
83		}
84		scenarioOnce.Do(func() {
85			scenarioResult, scenarioErr = runContentionScenario(t)
86		})
87		if scenarioErr != nil {
88			t.Fatalf("multi-worker lock-contention scenario failed: %v", scenarioErr)
89		}
90		return scenarioResult
91	}
