141	// TestIntegration_MultiWorkerLockContention_NoOperatorTimeouts asserts that no
142	// operator-issued bead command failed with a tracker-lock timeout.
143	func TestIntegration_MultiWorkerLockContention_NoOperatorTimeouts(t *testing.T) {
144		res := contentionScenario(t)
145		var timedOut []string
146		for _, c := range res.operatorOutput {
147			if c.timedOut() {
148				timedOut = append(timedOut, fmt.Sprintf("`ddx bead %s`: %s", c.args, strings.TrimSpace(c.output)))
149			}
150		}
151		if len(timedOut) > 0 {
152			t.Fatalf("%d operator command(s) failed with tracker lock timeout:\n%s",
153				len(timedOut), strings.Join(timedOut, "\n"))
154		}
155	}
