198	// runContentionScenario builds the fixture, spawns the workers and operators,
199	// drives them to completion, and returns the captured lock metrics + operator
200	// outcomes.
201	func runContentionScenario(t *testing.T) (*contentionResult, error) {
202		t.Helper()
203	
204		// Build ddx from the current source tree (not a possibly-stale `ddx` on
205		// PATH) and pin it so the fixture seeding and the spawned workers/operators
206		// all exercise the lock instrumentation under test.
207		bin := testutils.BuildDDxBinary(t)
208		t.Setenv("DDX_BIN", bin)
209		proj := testutils.NewFixtureRepo(t, "minimal")
210		ddxDir := ddxroot.JoinProject(proj)
211	
212		// The first `ddx work` would otherwise be blocked by auto-materialized
213		// project-local skill/schema files appearing as dirty implementation
214		// changes; ignore them so the worktree stays clean under the dirty guard.
215		if err := appendGitignore(proj, ".agents/", ".claude/", ".ddx/lifecycle-schema.json"); err != nil {
216			return nil, err
217		}
218		if err := gitCommitAll(proj, "test: ignore auto-materialized paths"); err != nil {
219			return nil, err
220		}
221	
222		// Subprocesses run with a minimal, isolated environment: an isolated HOME
223		// and XDG_DATA_HOME (so workers neither read the developer's ~/.ddx config
224		// nor register with this box's real ddx server), and a PATH restricted to
225		// git plus the standard system dirs. Restricting PATH is essential: with the
226		// full developer PATH, `ddx work`'s harness discovery probes whatever agent
227		// CLIs are installed (codex/claude/gemini), and at least one (gemini)
228		// daemonizes — a detached child that survives the worker and keeps writing
229		// under HOME, racing t.TempDir cleanup. The built-in `script` harness needs
230		// only git + sh, so excluding the agent CLIs keeps the run deterministic.
231		gitPath, err := exec.LookPath("git")
232		if err != nil {
233			return nil, fmt.Errorf("locate git: %w", err)
234		}
235		minimalPATH := strings.Join([]string{filepath.Dir(gitPath), "/usr/bin", "/bin", "/usr/sbin", "/sbin"}, string(os.PathListSeparator))
236		home := t.TempDir()
237		xdg := t.TempDir()
238		subprocessEnv := []string{
239			"HOME=" + home,
240			"XDG_DATA_HOME=" + xdg,
241			"PATH=" + minimalPATH,
242			"GIT_CONFIG_SYSTEM=/dev/null",
243			"GIT_TERMINAL_PROMPT=0",
244		}
245	
246		// Seed the worker queue with workerBeadCount independent ready beads.
247		workerBeads, err := createBeads(bin, proj, subprocessEnv, workerBeadCount, "Worker bead")
248		if err != nil {
249			return nil, fmt.Errorf("seed worker beads: %w", err)
250		}
251		if err := gitCommitAll(proj, "test: seed worker beads"); err != nil {
252			return nil, err
253		}
254	
255		// Directive run by the stubbed `script` harness: the sleep-ms mimics the
256		// LLM wait and happens OUTSIDE any lock; the create-file + commit are the
257		// only mutations, so the worker holds the index/tracker locks only briefly.
258		directive := filepath.Join(t.TempDir(), "directive.txt")
259		if err := os.WriteFile(directive, []byte(
260			"sleep-ms 400\n"+
261				"create-file out-${DDX_BEAD_ID}.txt done\n"+
262				"commit feat: ${DDX_BEAD_ID} work\n"), 0o644); err != nil {
263			return nil, fmt.Errorf("write directive: %w", err)
264		}
265	
266		// Spawn the 5 watcher processes.
267		workers := make([]*exec.Cmd, 0, workerCount)
268		for i := 0; i < workerCount; i++ {
269			cmd := exec.Command(bin, "work", "--watch",
270				"--idle-interval", "500ms",
271				"--harness", "script",
272				"--model", directive,
273				"--attempt-backend", "local-clone",
274				"--no-review", "--no-review-i-know-what-im-doing",
275				"--project", proj,
276			)
277			cmd.Dir = proj
278			cmd.Env = subprocessEnv
279			if err := cmd.Start(); err != nil {
280				stopWorkers(workers)
281				return nil, fmt.Errorf("start worker %d: %w", i, err)
282			}
283			workers = append(workers, cmd)
284		}
285		// Guarantee the watchers are reaped even if the scenario aborts midway.
286		defer stopWorkers(workers)
287	
288		// Concurrently hammer the tracker with 20 operator bead commands.
289		opDone := make(chan []operatorCommand, 1)
290		go func() {
291			opDone <- runOperatorCommands(bin, proj, subprocessEnv, operatorCount)
292		}()
293	
294		ops := <-opDone
295	
296		// Give the watchers a bounded window to drain the worker queue. The
297		// assertions do not require every worker bead to close (cross-process
298		// landing races can leave a bead retryable), but draining maximises the
299		// overlap window that produced the lock metrics.
300		waitForWorkerBeadsToDrain(ddxDir, workerBeads, 60*time.Second)
301	
302		// Stop the watchers and let their final metric writes flush.
303		stopWorkers(workers)
304	
305		events, err := lockmetrics.Load(proj)
306		if err != nil {
307			return nil, fmt.Errorf("load lock metrics: %w", err)
308		}
309		index, tracker := holdDurations(events)
310	
311		return &contentionResult{
312			indexHoldMS:    index,
313			trackerHoldMS:  tracker,
314			operatorOutput: ops,
315			workersSpawned: len(workers),
316		}, nil
317	}
318	
319	// runOperatorCommands issues `count` operator bead commands (create/update/
320	// close cycles on operator-owned beads) and returns each command's outcome.
321	func runOperatorCommands(bin, proj string, env []string, count int) []operatorCommand {
322		cmds := make([]operatorCommand, 0, count)
323		run := func(args ...string) operatorCommand {
324			c := exec.Command(bin, append([]string{"bead"}, args...)...)
325			c.Dir = proj
326			c.Env = env
327			out, err := c.CombinedOutput()
328			return operatorCommand{args: strings.Join(args, " "), output: string(out), err: err}
329		}
330		for len(cmds) < count {
331			create := run("create", fmt.Sprintf("Operator bead %d", len(cmds)),
332				"--priority", "2", "--description", "operator-issued work", "--acceptance", "ok")
333			cmds = append(cmds, create)
334			id := lastLine(create.output)
335			if create.err != nil || id == "" {
336				continue
337			}
338			if len(cmds) < count {
339				cmds = append(cmds, run("update", id, "--notes", "operator touch"))
340			}
341			if len(cmds) < count {
342				cmds = append(cmds, run("close", id))
343			}
344		}
345		return cmds
346	}
