348	// waitForWorkerBeadsToDrain polls until every worker bead is closed or the
349	// deadline elapses. It tolerates transient read errors from the concurrently
350	// mutated store.
351	func waitForWorkerBeadsToDrain(ddxDir string, ids []string, timeout time.Duration) {
352		store := bead.NewStore(ddxDir)
353		deadline := time.Now().Add(timeout)
354		for time.Now().Before(deadline) {
355			closed := 0
356			for _, id := range ids {
357				if b, err := store.Get(context.Background(), id); err == nil && b != nil && b.Status == bead.StatusClosed {
358					closed++
359				}
360			}
361			if closed == len(ids) {
362				return
363			}
364			time.Sleep(250 * time.Millisecond)
365		}
366	}
