368	// holdDurations splits release-event hold durations (milliseconds) by lock name.
369	func holdDurations(events []lockmetrics.Event) (index, tracker []float64) {
370		for _, ev := range events {
371			if ev.Event != "release" {
372				continue
373			}
374			switch ev.LockName {
375			case "index.lock":
376				index = append(index, float64(ev.DurationMS))
377			case "tracker.lock":
378				tracker = append(tracker, float64(ev.DurationMS))
379			}
380		}
381		return index, tracker
382	}
