459	// appendGitignore appends paths to the project's .gitignore.
460	func appendGitignore(proj string, paths ...string) error {
461		f, err := os.OpenFile(filepath.Join(proj, ".gitignore"), os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
462		if err != nil {
463			return fmt.Errorf("open .gitignore: %w", err)
464		}
465		defer f.Close() //nolint:errcheck
466		for _, p := range paths {
467			if _, err := fmt.Fprintln(f, p); err != nil {
468				return fmt.Errorf("write .gitignore: %w", err)
469			}
470		}
471		return nil
472	}
