474	// gitCommitAll stages everything and commits with signing disabled.
475	func gitCommitAll(proj, msg string) error {
476		for _, args := range [][]string{
477			{"add", "-A"},
478			{"-c", "commit.gpgsign=false", "commit", "-q", "-m", msg},
479		} {
480			cmd := exec.Command("git", append([]string{"-C", proj}, args...)...)
481			cmd.Env = append(os.Environ(), "GIT_CONFIG_SYSTEM=/dev/null")
482			if out, err := cmd.CombinedOutput(); err != nil {
483				// An empty commit (nothing staged) is not a failure for our setup.
484				if strings.Contains(string(out), "nothing to commit") {
485					continue
486				}
487				return fmt.Errorf("git %v: %v\n%s", args, err, out)
488			}
489		}
490		return nil
491	}
