39	// execution worktrees. It applies the configured worktree root when present and
40	// otherwise falls back to the user's cache directory, not the process temp dir.
41	func ExecutionTempRoot(projectRoot string) string {
42		if root := ExecutionWorktreeRoot(projectRoot); root != "" {
43			return root
44		}
45		if cacheDir, err := os.UserCacheDir(); err == nil && strings.TrimSpace(cacheDir) != "" {
46			return filepath.Join(cacheDir, "ddx", "exec-wt")
47		}
48		return LegacyExecutionTempRoot()
49	}
50	
51	// LegacyExecutionTempRoot is the pre-centralization $TMPDIR root. New
52	// execution paths should not use it directly; cleanup and worktree detection
53	// keep scanning it so older leaked resources are not stranded.
54	func LegacyExecutionTempRoot() string {
55		return filepath.Join(os.TempDir(), DefaultExecutionTempSubdir)
56	}
57	
58	// ExecutionScratchRoot returns the directory for short-lived helper scratch
59	// paths associated with execution. Scratch lives beside the worktree root so a
60	// configured root such as /var/tmp/ddx-exec-wt keeps all DDx-owned temporary
61	// paths away from /tmp while still grouping attempt worktrees under one child.
62	func ExecutionScratchRoot(projectRoot string) string {
63		root := filepath.Dir(filepath.Clean(ExecutionTempRoot(projectRoot)))
64		if root == "" || root == "." {
65			return os.TempDir()
66		}
67		return root
68	}
69	
70	// MkdirExecutionScratch creates a DDx-owned scratch directory under the
71	// configured execution scratch root.
72	func MkdirExecutionScratch(projectRoot, pattern string) (string, error) {
73		root := ExecutionScratchRoot(projectRoot)
74		if err := os.MkdirAll(root, 0o755); err != nil {
75			return "", err
76		}
77		return os.MkdirTemp(root, pattern)
78	}
79	
80	// CreateExecutionScratch creates a DDx-owned scratch file under the configured
81	// execution scratch root.
82	func CreateExecutionScratch(projectRoot, pattern string) (*os.File, error) {
83		root := ExecutionScratchRoot(projectRoot)
84		if err := os.MkdirAll(root, 0o755); err != nil {
85			return nil, err
86		}
87		return os.CreateTemp(root, pattern)
88	}
89	
90	func executionWorktreeRootFromFile(path, relativeBase string) string {
91		if strings.TrimSpace(path) == "" {
92			return ""
93		}
94		cfg, err := LoadFromFile(path)
95		if err != nil || cfg == nil || cfg.Executions == nil {
96			return ""
97		}
98		return normalizeExecutionWorktreeRoot(cfg.Executions.TempWorktreeRoot, relativeBase)
99	}
100	
101	func normalizeExecutionWorktreeRoot(path, relativeBase string) string {
102		path = strings.TrimSpace(path)
103		if path == "" {
104			return ""
105		}
106		if path == "~" {
107			if home, err := os.UserHomeDir(); err == nil && home != "" {
108				path = home
109			}
110		} else if strings.HasPrefix(path, "~/") {
111			if home, err := os.UserHomeDir(); err == nil && home != "" {
112				path = filepath.Join(home, strings.TrimPrefix(path, "~/"))
113			}
114		}
115		if !filepath.IsAbs(path) && strings.TrimSpace(relativeBase) != "" {
116			path = filepath.Join(relativeBase, path)
117		}
118		return filepath.Clean(path)
119	}
