// spawnTry launches a single `ddx try <beadID>` subprocess and returns the
// started *exec.Cmd with stdout/stderr captured in buf. Callers must call
// cmd.Wait() to collect the exit code and release resources.
func spawnTry(bin, proj, beadID, harness, directive string, env []string) (*exec.Cmd, *bytes.Buffer) {
	buf := &bytes.Buffer{}
	cmd := exec.Command(bin, "try", beadID,
		"--harness", harness,
		"--model", directive,
		"--attempt-backend", "local-clone",
		"--no-review", "--no-review-i-know-what-im-doing",
		"--project", proj,
	)
	cmd.Dir = proj
	cmd.Env = env
	cmd.Stdout = buf
	cmd.Stderr = buf
	return cmd, buf
}

