3	// concurrent_try_test.go — subprocess integration tests for concurrent ddx try
4	// invocations as required by TP-021-multi-worker-try-reliability.md.
5	//
6	// Three test functions are provided (each satisfying one TP-021 integration AC):
7	//
8	//   TestIntegration_ConcurrentTryDistinctBeads_LocalClone
9	//   TestIntegration_ConcurrentTrySameBead_OneClaimWins
10	//   TestIntegration_ConcurrentTryPreserveRefsUnique
11	//
12	// All three use testutils.BuildDDxBinary, fixture repositories, and the
13	// deterministic `script` harness with an isolated HOME/XDG_DATA_HOME. None of
14	// them require network access or external agent CLIs.
15	
16	import (
17		"bytes"
18		"os"
19		"os/exec"
20		"path/filepath"
21		"strings"
22		"sync"
23		"testing"
24	
25		"github.com/DocumentDrivenDX/ddx/internal/testutils"
26	)
27	
28	// subprocessEnvFor builds the minimal isolated subprocess environment used by
29	// all concurrent-try tests. HOME and XDG_DATA_HOME are set to fresh temp dirs
30	// so workers do not read real developer config or register with the local
31	// ddx-server. PATH is stripped to git + standard system directories so agent
32	// CLIs (codex, claude, gemini) cannot be discovered and daemonised.
33	func subprocessEnvFor(t *testing.T, bin string) (env []string, home, xdg string) {
34		t.Helper()
35		gitPath, err := exec.LookPath("git")
36		if err != nil {
37			t.Fatalf("subprocessEnvFor: locate git binary: %v", err)
38		}
39		minimalPATH := strings.Join(
40			[]string{filepath.Dir(gitPath), filepath.Dir(bin), "/usr/bin", "/bin", "/usr/sbin", "/sbin"},
41			string(os.PathListSeparator),
42		)
43		home = t.TempDir()
44		xdg = t.TempDir()
45		env = []string{
46			"HOME=" + home,
47			"XDG_DATA_HOME=" + xdg,
48			"PATH=" + minimalPATH,
49			"GIT_CONFIG_SYSTEM=/dev/null",
50			"GIT_TERMINAL_PROMPT=0",
51		}
52		return env, home, xdg
53	}
54	
55	// spawnTry launches a single `ddx try <beadID>` subprocess and returns the
56	// started *exec.Cmd with stdout/stderr captured in buf. Callers must call
57	// cmd.Wait() to collect the exit code and release resources. extraFlags are
58	// appended to the base flags (e.g. "--from <sha>").
59	func spawnTry(bin, proj, beadID, harness, directive string, env []string, extraFlags ...string) (*exec.Cmd, *bytes.Buffer) {
60		buf := &bytes.Buffer{}
61		args := []string{"try", beadID,
62			"--harness", harness,
63			"--model", directive,
64			"--attempt-backend", "local-clone",
65			"--no-review", "--no-review-i-know-what-im-doing",
66			"--project", proj,
67		}
68		args = append(args, extraFlags...)
69		cmd := exec.Command(bin, args...)
70		cmd.Dir = proj
71		cmd.Env = env
72		cmd.Stdout = buf
73		cmd.Stderr = buf
74		return cmd, buf
75	}
76	
77	// cloneAttemptDirs returns the paths of any lingering .execute-bead-clone-*
78	// directories under the subprocess's cache area (HOME/.cache/ddx/exec-wt/).
79	// A subprocess that exits cleanly should remove these; they are only present
80	// during an active attempt or if cleanup failed.
81	func cloneAttemptDirs(home string) ([]string, error) {
82		cloneRoot := filepath.Join(home, ".cache", "ddx", "exec-wt")
83		entries, err := os.ReadDir(cloneRoot)
84		if os.IsNotExist(err) {
85			return nil, nil
86		}
87		if err != nil {
88			return nil, err
89		}
90		var found []string
91		for _, e := range entries {
92			if strings.HasPrefix(e.Name(), ".execute-bead-clone-") {
93				found = append(found, filepath.Join(cloneRoot, e.Name()))
94			}
95		}
96		return found, nil
97	}
