99	// parsePreserveRef extracts the preserve_ref value from ddx try output.
100	func parsePreserveRef(output string) string {
101		const prefix = "preserve_ref: "
102		for _, line := range strings.Split(output, "\n") {
103			trimmed := strings.TrimSpace(line)
104			if strings.HasPrefix(trimmed, prefix) {
105				return strings.TrimSpace(strings.TrimPrefix(trimmed, prefix))
106			}
107		}
108		return ""
109	}
