111	// gitRunIn runs a git command in dir and returns its output, fatally failing t
112	// on error. env defaults to the current process environment.
113	func gitRunIn(t *testing.T, dir string, args ...string) string {
114		t.Helper()
115		cmd := exec.Command("git", append([]string{"-C", dir}, args...)...)
116		cmd.Env = append(os.Environ(), "GIT_CONFIG_SYSTEM=/dev/null")
117		out, err := cmd.CombinedOutput()
118		if err != nil {
119			// An "empty commit" is not a test failure.
120			if strings.Contains(string(out), "nothing to commit") {
121				return string(out)
122			}
123			t.Fatalf("git %v in %s: %v\n%s", args, dir, err, out)
124		}
125		return strings.TrimSpace(string(out))
126	}
