128	// TestIntegration_ConcurrentTryDistinctBeads_LocalClone satisfies TP-021 AC1.
129	//
130	// Seeds 8 independent beads and runs 4 concurrent `ddx try <id>` subprocesses
131	// (each targeting a distinct bead) with the script harness and
132	// --attempt-backend local-clone. Asserts:
133	//
134	//   - all 4 subprocesses exit (success or preserved)
135	//   - attempt IDs (derived from evidence bundle names) are unique
136	//   - no lingering .execute-bead-clone-* directories remain after all
137	//     subprocesses exit
138	func TestIntegration_ConcurrentTryDistinctBeads_LocalClone(t *testing.T) {
139		if testing.Short() {
140			t.Skip("integration: spawns ddx try subprocesses")
141		}
142	
143		bin := testutils.BuildDDxBinary(t)
144		t.Setenv("DDX_BIN", bin)
145		proj := testutils.NewFixtureRepo(t, "minimal")
146		env, home, _ := subprocessEnvFor(t, bin)
147	
148		// Suppress auto-materialized paths so the initial tree stays clean.
149		if err := appendGitignore(proj, ".agents/", ".claude/", ".ddx/lifecycle-schema.json"); err != nil {
150			t.Fatalf("append gitignore: %v", err)
151		}
152		if err := gitCommitAll(proj, "test: ignore auto-materialized paths"); err != nil {
153			t.Fatalf("initial commit: %v", err)
154		}
155	
156		// Seed 8 independent beads so there is no queue contention.
157		const totalBeads = 8
158		const concurrentWorkers = 4
159		beadIDs, err := createBeads(bin, proj, env, totalBeads, "Concurrent try distinct bead")
160		if err != nil {
161			t.Fatalf("seed beads: %v", err)
162		}
163		if err := gitCommitAll(proj, "test: seed distinct beads"); err != nil {
164			t.Fatalf("commit beads: %v", err)
165		}
166	
167		// Directive: simulate an LLM wait outside the lock, then create a file and
168		// commit so there are meaningful changes to land.
169		directive := filepath.Join(t.TempDir(), "directive.txt")
170		if err := os.WriteFile(directive, []byte(
171			"sleep-ms 300\n"+
172				"create-file out-${DDX_BEAD_ID}.txt done\n"+
173				"commit feat: ${DDX_BEAD_ID} done\n"), 0o644); err != nil {
174			t.Fatalf("write directive: %v", err)
175		}
176	
177		// Run concurrentWorkers concurrent ddx try subprocesses against distinct beads.
178		type result struct {
179			beadID string
180			output string
181			code   int
182		}
183		results := make([]result, concurrentWorkers)
184		var wg sync.WaitGroup
185		for i := 0; i < concurrentWorkers; i++ {
186			wg.Add(1)
187			go func(idx int) {
188				defer wg.Done()
189				bid := beadIDs[idx]
190				cmd, buf := spawnTry(bin, proj, bid, "script", directive, env)
191				if err := cmd.Start(); err != nil {
192					t.Errorf("start try for bead %s: %v", bid, err)
193					return
194				}
195				_ = cmd.Wait()
196				code := 0
197				if cmd.ProcessState != nil {
198					code = cmd.ProcessState.ExitCode()
199				}
200				results[idx] = result{beadID: bid, output: buf.String(), code: code}
201			}(i)
202		}
203		wg.Wait()
204	
205		// All 4 subprocesses must have exited (code 0=success, 1=preserved, 2=other).
206		// We accept both 0 and 1 because a concurrent land race can preserve a
207		// result (another worker on a shared fixture may have advanced the branch).
208		// Code 2 (unexpected failure) is always an error.
209		for i, r := range results {
210			if r.code == 2 {
211				t.Errorf("worker %d (bead %s) exited with code 2 (unexpected failure):\n%s", i, r.beadID, r.output)
212			}
213		}
214	
215		// No lingering clone attempt directories after all subprocesses exit.
216		lingering, err := cloneAttemptDirs(home)
217		if err != nil {
218			t.Fatalf("reading clone attempt dirs: %v", err)
219		}
220		if len(lingering) > 0 {
221			t.Errorf("lingering attempt directories after all subprocesses exited:\n%s",
222				strings.Join(lingering, "\n"))
223		}
224	
225		// Attempt IDs must be unique. Collect them from the evidence bundle
226		// directory names under .ddx/executions/.
227		executionsDir := filepath.Join(proj, ".ddx", "executions")
228		entries, err := os.ReadDir(executionsDir)
229		if err != nil && !os.IsNotExist(err) {
230			t.Fatalf("reading executions dir: %v", err)
231		}
232		seen := map[string]bool{}
233		var attemptIDs []string
234		for _, e := range entries {
235			if !e.IsDir() {
236				continue
237			}
238			name := e.Name()
239			// Evidence bundle dirs are named with the attempt ID (a timestamp-hex string).
240			if name == "reviewer-streams" || name == "mirror-index.jsonl" {
241				continue
242			}
243			if seen[name] {
244				t.Errorf("duplicate attempt ID in evidence dirs: %s", name)
245			}
246			seen[name] = true
247			attemptIDs = append(attemptIDs, name)
248		}
249		// At least concurrentWorkers evidence entries must exist (one per attempt).
250		if len(attemptIDs) < concurrentWorkers {
251			t.Errorf("expected at least %d evidence bundle dirs, found %d", concurrentWorkers, len(attemptIDs))
252		}
253	}
