// TestIntegration_ConcurrentTryPreserveRefsUnique satisfies TP-021 AC3.
//
// Forces two sequential non-landed attempts by pinning both to a stale base
// revision (--from <sha>) so the land always encounters a merge conflict.
// No timing-based injection is needed: the conflicting commit is committed to
// the main branch before the subprocesses start; the --from flag directs the
// local-clone backend to check out the stale SHA, so the worker's result
// diverges from main and every land attempt fails with a merge conflict.
//
// Proves that refs under refs/ddx/iterations/<bead-id>/ are unique even when
// attempts start within the same second. Uniqueness is guaranteed because the
// land path uses attemptID (timestamp+4-byte-random) in the ref name via
// landIterationRef, not a second-precision timestamp alone.
func TestIntegration_ConcurrentTryPreserveRefsUnique(t *testing.T) {
	if testing.Short() {
		t.Skip("integration: spawns ddx try subprocesses")
	}

	bin := testutils.BuildDDxBinary(t)
	t.Setenv("DDX_BIN", bin)
	proj := testutils.NewFixtureRepo(t, "minimal")
	env, _, _ := subprocessEnvFor(t, bin)

	if err := appendGitignore(proj, ".agents/", ".claude/", ".ddx/lifecycle-schema.json"); err != nil {
		t.Fatalf("append gitignore: %v", err)
	}

	// Step 1: create conflict.txt.
	conflictFile := filepath.Join(proj, "conflict.txt")
	if err := os.WriteFile(conflictFile, []byte("initial\n"), 0o644); err != nil {
		t.Fatalf("write conflict.txt: %v", err)
	}
	if err := gitCommitAll(proj, "test: add conflict.txt and gitignore"); err != nil {
		t.Fatalf("initial commit: %v", err)
	}

	// Step 2: create and commit the bead (so the bead exists in the JSONL at staleSHA).
	beadIDs, err := createBeads(bin, proj, env, 1, "Preserve ref uniqueness")
	if err != nil {
		t.Fatalf("seed bead: %v", err)
	}
	if err := gitCommitAll(proj, "test: seed bead"); err != nil {
		t.Fatalf("commit bead: %v", err)
	}
	beadID := beadIDs[0]

	// Capture staleSHA AFTER the bead commit so the clone at staleSHA can find
	// the bead in .ddx/beads.jsonl but conflict.txt is still at "initial\n".
	staleSHA := gitRunIn(t, proj, "rev-parse", "HEAD")

	// Step 3: advance main with a conflicting change to conflict.txt. Workers
	// pinned to staleSHA will commit "worker-version" on top of staleSHA, while
	// main now has "main-advanced-version" → the merge always conflicts.
	if err := os.WriteFile(conflictFile, []byte("main-advanced-version\n"), 0o644); err != nil {
		t.Fatalf("write conflict.txt for advance: %v", err)
	}
	if err := gitCommitAll(proj, "test: advance main with conflicting conflict.txt"); err != nil {
		t.Fatalf("advance commit: %v", err)
	}

	// Directive: overwrite conflict.txt and commit (exits cleanly so the land
	// path is attempted). The worker is based on staleSHA where conflict.txt=
	// "initial\n"; main is ahead with "main-advanced-version\n"; the merge
	// produces a conflict → landIterationRef creates a preserve ref.
	directive := filepath.Join(t.TempDir(), "directive.txt")
	if err := os.WriteFile(directive, []byte(
		"create-file conflict.txt worker-version\n"+
			"commit chore: worker attempt\n"), 0o644); err != nil {
		t.Fatalf("write directive: %v", err)
	}

	var allPreserveRefs []string

	// Run two sequential attempts, each pinned to staleSHA via --from.
	// Both must produce a preserve ref; refs must be unique (different
	// attemptIDs) even when both attempts complete within the same second.
	for attempt := 0; attempt < 2; attempt++ {
		cmd, buf := spawnTry(bin, proj, beadID, "script", directive, env,
			"--from", staleSHA,
			"--force-claim", "--reason", "preserve-ref-uniqueness-test",
		)
		if startErr := cmd.Start(); startErr != nil {
			t.Fatalf("start try for attempt %d: %v", attempt, startErr)
		}
		_ = cmd.Wait()

		// Log all attempt output for diagnosis.
		t.Logf("attempt %d output:\n%s", attempt, buf.String())

		// Parse preserve_ref from the combined output. The ddx try command prints
		// "preserve_ref: <ref>" when the land path creates a hidden iteration ref.
		ref := parsePreserveRef(buf.String())
		if ref == "" {
			t.Fatalf("attempt %d: no preserve_ref found in output; land may have succeeded or the attempt errored before landing", attempt)
		}
		allPreserveRefs = append(allPreserveRefs, ref)
	}

	// Verify both refs are prefixed correctly.
	prefix := "refs/ddx/iterations/" + beadID + "/"
	for _, ref := range allPreserveRefs {
		if !strings.HasPrefix(ref, prefix) {
			t.Errorf("preserve ref %q does not start with expected prefix %q", ref, prefix)
		}
	}

	// Verify refs are unique (uniqueness proof for same-second scenarios).
	seen := map[string]bool{}
	for _, ref := range allPreserveRefs {
		if seen[ref] {
			t.Errorf("duplicate preserve ref detected: %q (refs must be unique even within the same second)", ref)
		}
		seen[ref] = true
	}

	// Verify each ref exists and resolves in git.
	for _, ref := range allPreserveRefs {
		sha := gitRunIn(t, proj, "rev-parse", "--verify", ref)
		if sha == "" {
			t.Errorf("preserve ref %q not resolvable in git repo", ref)
		}
	}
}

